The current screen shows Notepad++ open, which is suitable for writing scripts. The task is to create and run a Photoshop script that draws a basic face and saves the file as 'agent created figure.psd'. The first step is to write the script. In Notepad++, I should type the JavaScript (ExtendScript) code for Photoshop to draw a basic face (e.g., a circle for the head, two circles for eyes, and a curve for the mouth), and save the file. I will start by typing the script.
var doc = app.documents.add(500, 500, 72, 'agent created figure');
var head = doc.artLayers.add();
head.kind = LayerKind.NORMAL;
app.activeDocument.selection.select([[150, 100], [350, 100], [350, 300], [150, 300]]);
app.activeDocument.selection.ellipse(150, 100, 200, 200);
app.activeDocument.selection.fill(app.foregroundColor);
app.activeDocument.selection.deselect();
// Eyes
var eye1 = doc.artLayers.add();
app.activeDocument.selection.ellipse(200, 170, 30, 30);
app.activeDocument.selection.fill(app.foregroundColor);
app.activeDocument.selection.deselect();
var eye2 = doc.artLayers.add();
app.activeDocument.selection.ellipse(270, 170, 30, 30);
app.activeDocument.selection.fill(app.foregroundColor);
app.activeDocument.selection.deselect();
// Mouth
var mouth = doc.artLayers.add();
app.activeDocument.selection.ellipse(220, 240, 60, 30);
app.activeDocument.selection.clear();
app.activeDocument.selection.deselect();
doc.saveAs(new File(app.activeDocument.path + '/agent created figure.psd'));
doc.close();

